function parseMaybeJson(value, fallback = {}) {
  if (value && typeof value === "object") return value;

  if (typeof value !== "string") return fallback;

  try {
    return JSON.parse(value);
  } catch {
    return fallback;
  }
}

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return value;
    }
  }
  return null;
}

const input = parseMaybeJson($json.payload, $json);

const ctx = input.execution_context || {};
const contextPacket = input.context_packet || {};
const lead = contextPacket.lead || {};
const state = contextPacket.state || {};
const conversation = contextPacket.conversation || {};
const decision = input.decision || {};
const decisionStateUpdate = decision.state_update || {};
const inputStateUpdate = input.state_update || {};

const leadId = firstValue(
  ctx.lead_id,
  lead.id,
  input.lead_id
);

const channel = firstValue(
  ctx.channel,
  lead.channel,
  input.channel,
  "whatsapp"
);

const phone = firstValue(
  ctx.phone,
  lead.phone,
  input.phone
);

if (!leadId) {
  throw new Error("Missing lead_id in recommend_service");
}

if (!channel) {
  throw new Error("Missing channel in recommend_service");
}

const normalizedExecutionContext = {
  ...ctx,

  lead_id: leadId,
  channel,
  phone,
  action: "recommend_service",

  service_interest: firstValue(
    ctx.service_interest,
    decisionStateUpdate.service_interest,
    inputStateUpdate.service_interest,
    state.service_interest
  ),

  vehicle_type: firstValue(
    ctx.vehicle_type,
    decisionStateUpdate.vehicle_type,
    inputStateUpdate.vehicle_type,
    state.vehicle_type
  ),

  district: firstValue(
    ctx.district,
    decisionStateUpdate.district,
    inputStateUpdate.district,
    state.district
  ),

  customer_need: firstValue(
    ctx.customer_need,
    decision.customer_need,
    decisionStateUpdate.customer_need,
    inputStateUpdate.customer_need,
    conversation.latest_user_message
  )
};

return [{
  ...input,

  lead_id: leadId,
  channel,
  phone,

  execution_context: normalizedExecutionContext,
  context_packet: contextPacket,
  decision,

  state_update: {
    ...decisionStateUpdate,
    ...inputStateUpdate
  }
}];

const data = $json;
const ctx = data.execution_context || {};
const state = data.context_packet?.state || {};
const conversation = data.context_packet?.conversation || {};

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && String(value).trim() !== "") {
      return String(value).trim();
    }
  }
  return null;
}

function normalizeText(value) {
  return String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function serviceLabel(service) {
  const map = {
    lavado_esencial: "lavado de mantención",
    lavado_profundo: "lavado profundo",
    lavado_premium: "lavado premium"
  };

  return map[service] || service || "servicio";
}

const vehicleType = firstValue(ctx.vehicle_type, state.vehicle_type);
const district = firstValue(ctx.district, state.district);
const latestMessage = firstValue(
  ctx.customer_need,
  conversation.latest_user_message,
  data.decision?.message,
  ""
);

const normalized = normalizeText(latestMessage);

const missingFields = [];

if (!vehicleType) missingFields.push("vehicle_type");
if (!district) missingFields.push("district");

function inferRecommendedService(text) {
  const premiumSignals = [
    "premium",
    "completo",
    "lo mejor",
    "full",
    "detallado",
    "impecable",
    "muy sucio",
    "demasiado sucio",
    "manchado",
    "manchas",
    "olor",
    "mas completo",
    "más completo",
    "dejarlo como nuevo",
    "vender el auto",
    "regalo",
    "especial"
  ];

  const deepSignals = [
    "profundo",
    "bien limpio",
    "harto tiempo",
    "mucho tiempo",
    "sucio",
    "interior",
    "aspirado",
    "normal pero bueno",
    "algo bueno",
    "terminacion buena",
    "terminación buena"
  ];

  const basicSignals = [
    "barato",
    "economico",
    "económico",
    "mantencion",
    "mantención",
    "rapido",
    "rápido",
    "simple",
    "basico",
    "básico",
    "por fuera",
    "mantener"
  ];

  if (premiumSignals.some(signal => text.includes(normalizeText(signal)))) {
    return "lavado_premium";
  }

  if (deepSignals.some(signal => text.includes(normalizeText(signal)))) {
    return "lavado_profundo";
  }

  if (basicSignals.some(signal => text.includes(normalizeText(signal)))) {
    return "lavado_esencial";
  }

  return "lavado_profundo";
}

const recommendedService = inferRecommendedService(normalized);

let message = "";

if (missingFields.length > 0) {
  message =
    "Sí, te puedo recomendar el servicio más conveniente. Para hacerlo bien, necesito dos datos: qué tipo de vehículo tienes y en qué comuna sería el servicio.\n\n" +
    "Con eso te digo si te conviene más el lavado de mantención, el lavado profundo o el lavado premium.";

  return [{
    ...data,

    message_to_send: message,

    db_operations: ["messages", "lead_state"],

    state_update: {
      ...(data.state_update || {}),

      stage: "service_discovery",
      intent_last: "service_recommendation_requested",
      next_goal: "collect_vehicle_and_district",
      last_bot_action: "recommend_service",

      vehicle_type: vehicleType || null,
      district: district || null,
      missing_fields: missingFields
    },

    execution_context: {
      ...ctx,
      action: "recommend_service"
    },

    execution_result: {
      success: true,
      action: "recommend_service",
      message_sent: false,
      state_updated: true,
      db_records_created: ["messages", "lead_state"],
      notes: ["recommendation_needs_vehicle_or_district"]
    },

    notes: ["recommendation_needs_vehicle_or_district"]
  }];
}

const reasonByService = {
  lavado_esencial:
    "porque sirve bien cuando buscas una limpieza de mantención, rápida y práctica, sin entrar en una limpieza tan detallada.",

  lavado_profundo:
    "porque es un punto medio muy conveniente: limpia mejor que una mantención básica y sirve cuando el auto necesita una limpieza más completa por dentro y por fuera.",

  lavado_premium:
    "porque es la opción más completa, pensada para cuando quieres una terminación más cuidada y un resultado más detallado."
};

message =
  `Para tu ${vehicleType} en ${district}, te recomendaría el ${serviceLabel(recommendedService)}, ` +
  `${reasonByService[recommendedService]}\n\n` +
  "Si quieres, ahora puedo darte el valor o revisar los horarios disponibles para agendar.";

return [{
  ...data,

  message_to_send: message,

  db_operations: ["messages", "lead_state"],

  state_update: {
    ...(data.state_update || {}),

    stage: "qualified",
    intent_last: "service_recommendation_requested",
    next_goal: "quote_or_offer_slots",
    last_bot_action: "recommend_service",

    service_interest: recommendedService,
    vehicle_type: vehicleType,
    district: district,

    missing_fields: []
  },

  execution_context: {
    ...ctx,
    action: "recommend_service",
    service_interest: recommendedService,
    vehicle_type: vehicleType,
    district: district
  },

  recommendation: {
    recommended_service: recommendedService,
    vehicle_type: vehicleType,
    district: district,
    source: "rule_based_recommendation"
  },

  execution_result: {
    success: true,
    action: "recommend_service",
    message_sent: false,
    state_updated: true,
    db_records_created: ["messages", "lead_state"],
    notes: ["service_recommendation_sent"]
  },

  notes: ["service_recommendation_sent"]
}];

